import 'prosekit/basic/style.css'
import 'prosekit/basic/typography.css'

import { defineBasicExtension } from 'prosekit/basic'
import { createEditor } from 'prosekit/core'
import { ProseKit } from 'prosekit/solid'
import type { JSX } from 'solid-js'

import { InlineMenu } from '../../ui/inline-menu'

import ExtensionComponent from './extension-component.tsx'

export default function EditorComponent(props: {
  placeholder: string
}): JSX.Element {
  const extension = defineBasicExtension()
  const editor = createEditor({ extension })

  return (
    <ProseKit editor={editor}>
      <div class="box-border h-full w-full min-h-36 overflow-y-hidden overflow-x-hidden rounded-md border border-solid border-gray-200 dark:border-gray-700 shadow-sm flex flex-col bg-white dark:bg-gray-950 text-black dark:text-white">
        <div class="relative w-full flex-1 box-border overflow-y-auto">
          <div ref={editor.mount} class="ProseMirror box-border min-h-full px-[max(4rem,calc(50%-20rem))] py-8 outline-hidden outline-0 [&_span[data-mention=user]]:text-blue-500 [&_span[data-mention=tag]]:text-violet-500"></div>
          <InlineMenu />
        </div>
      </div>
      <ExtensionComponent placeholder={props.placeholder} />
    </ProseKit>
  )
}

import { createSignal, For, type JSX } from 'solid-js'

import EditorComponent from './editor-component'

export default function Editor(): JSX.Element {
  let nextKey = 1
  const [editorKeys, setEditorKeys] = createSignal<number[]>([])

  const addEditor = () => {
    const key = nextKey
    nextKey += 1
    setEditorKeys((keys) => [...keys, key])
  }

  const removeEditor = (key: number) => {
    setEditorKeys((keys) => keys.filter((k) => k !== key))
  }

  return (
    <div class="flex flex-col gap-2">
      <div class="flex gap-2">
        <button onClick={addEditor} class="border p-2">
          Add editor
        </button>
        <For each={editorKeys()}>
          {(key) => (
            <button
              onClick={() => removeEditor(key)}
              class="border p-2"
            >
              Unmount No.{key}
            </button>
          )}
        </For>
      </div>
      <For each={editorKeys()}>
        {(key) => (
          <div>
            <EditorComponent
              placeholder={`Editor No.${key}`}
            />
          </div>
        )}
      </For>
    </div>
  )
}

import { definePlaceholder } from 'prosekit/extensions/placeholder'
import { useExtension } from 'prosekit/solid'
import { createMemo, type JSX } from 'solid-js'

export default function ExtensionComponent(props: {
  placeholder: string
}): JSX.Element {
  const extension = createMemo(() => {
    return definePlaceholder({ placeholder: props.placeholder })
  })

  useExtension(extension)

  return null
}
